#include <bits/stdc++.h>
#define int long long
using namespace std;
#define M 10000007
int N, Ans = 1;
int C, G[50];
int qPow (int b, int e) {
	int A = 1;
	for (; e; b = b * b % M, e >>= 1) {
		e & 1 ? A = A * b % M : 0;
	}
	return A;
}
signed main() {
	ios::sync_with_stdio (0);
	cin.tie (0), cout.tie (0);
	cin >> N;
	for (int j = 49; ~j; j--) {
		for (int i = 49; i; i--) {
			G[i] += G[i - 1];
		}
		if (N >> j & 1) {
			++G[C++];
		}
	}
	++G[C];
	for (int i = 1; i <= 49; i++) {
		Ans = Ans * qPow (i, G[i]) % M;
	}
	cout << Ans;
	return 0;
}
